package ru.memearena.tournament.api; import jakarta.validation.*; import org.springframework.data.domain.*; import org.springframework.http.*; import org.springframework.security.core.context.SecurityContextHolder; import org.springframework.web.bind.annotation.*; import ru.memearena.security.*; import ru.memearena.tournament.application.*; import java.util.*; @RestController @RequestMapping("/api/v1/tournaments") public class TournamentController{ private final TournamentQueryService query; private final TournamentVoteService votes; public TournamentController(TournamentQueryService q,TournamentVoteService v){query=q;votes=v;} private Optional<UUID> user(){var a=SecurityContextHolder.getContext().getAuthentication();return a!=null&&a.getPrincipal() instanceof AuthenticatedUserPrincipal p?Optional.of(p.userId()):Optional.empty();} @GetMapping("/current") public Object current(){return query.current(user());} @GetMapping("/{id}") public Object byId(@PathVariable UUID id){return query.byId(id,user());} @GetMapping("/history") public Object history(@RequestParam(defaultValue="0") int page,@RequestParam(defaultValue="20") int size){return query.history(PageRequest.of(page,size));} @PostMapping("/matches/{matchId}/votes") public ResponseEntity<TournamentVoteResponse> vote(@PathVariable UUID matchId,@Valid @RequestBody TournamentVoteRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(votes.vote(matchId,CurrentUser.required().userId(),r.selectedMemeId()));} }
